class Solution {
public:
    int countBinarySubstrings(string s) {
        int n = s.size();
        int res = 0;
        vector<int> groups;
        int prev = 0, curr = 1;

        for (int i = 1; i < n; i++) {
            if (s[i] == s[i - 1]) curr++;
            else {
                groups.push_back(curr - prev);
                prev = curr;
                curr = 1;
            }
        }

        groups.push_back(curr - prev);

        for (int i = 1; i < groups.size(); i++)
            res += min(groups[i - 1], groups[i]);

        return res;
    }
};
